(window.courseContentFiles = window.courseContentFiles || {})["000002/0011"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Теми по ревматология</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.8em;\n      margin-bottom: 0.15em;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0.1em; }\n    h4 { font-size: 1.05em; margin-bottom: 0.1em; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.2em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    p + ul, p + ol { margin-top: -0.5em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0.1em; \n    }\n    ul, ol { \n      margin: 0.5em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image styles are handled by inline styles and data-width attributes */\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n      line-height: 1 !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.3em; }\n      h2 { font-size: 1.1em; }\n      h3 { font-size: 1em; }\n      p { margin: 0.5em 0; }\n      ul, ol { padding-left: 1.2em; }\n      li { margin: 0.1em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 4px 6px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: left\"><p style=\"text-align: center\">Тема 39: Анкилозиращ спондилартрит – етиология, клинична форма, усложнения и лечение.</p></h1><p style=\"text-align: left\"><span style=\"color: rgb(31, 41, 55)\">Анкилозиращият спондилит (АС) е прототип на серонегативните спондилартропатии. </span>Това е <strong>системно хронично възпалително заболяване</strong>, което уврежда <strong>аскиалния скелет </strong>и <strong>сакроилиачните стави</strong>. Рядко засяга ставите на крайниците, с изключение на тазобедрените и раменните. Съпътства се от различни извънскелетни прояви.</p><h2></h2><h2><hr></h2><h2></h2><h2>Етиология:</h2><p>Заболяването възниква в резултат на взаимодействие между наследствени фактори и инфекциозни агенти.</p><h3>1. Генетичен фактор (HLA-B27)</h3><ul><li><strong>Ключов маркер:</strong> Над <strong>90-95%</strong> от пациентите са носители на антигена <strong>HLA-B27</strong>.</li><li><strong>Важно:</strong> Носителството е основен етиологичен елемент, но само по себе си не гарантира развитие на болестта.</li></ul><h3>2. Хипотеза за „Молекулярна мимикрия“ (Klebsiella)</h3><ul><li><strong>Чревен имунитет:</strong> Повишеният <strong>серумен IgA</strong> при болните подсказва преминаване на чревни микроби в кръвта.</li><li><strong>Механизъм:</strong> Бактерията <strong>Klebsiella</strong> притежава молекули, почти идентични с HLA-B27.</li><li><strong>Кръстосана реактивност:</strong>&nbsp;<strong>М</strong><strong>олекулярна мимикрия </strong>води до това&nbsp;антителата, атакуващи бактерията, да започват да рушат собствените тъкани на организма.</li></ul><hr><h2>Епидемиология</h2><ul><li><strong>Възраст на начало:</strong> Обикновено започва през <strong>тийнейджърските години и 20-те години</strong>.</li><li><strong>Пол:</strong> Мъжете боледуват <strong>2 до 3 пъти по-често</strong> от жените.</li><li><strong>Фамилност:</strong> Висок риск при роднини по права линия, свързан с наследяването на <strong>HLA-B27</strong>.</li></ul><br><hr><h2></h2><h2></h2><h3>Клинична картина</h3><p>Анкилозиращият спондилит (АС) протича като хронично възпалително заболяване с характерна еволюция на симптомите от долните части на гръбнака нагоре.</p><h3>1. Ранни симптоми и характеристика на болката</h3><ul><li><strong><span class=\"editor-note\" data-note=\"**Разграничаване на възпалителна и механична болка в гърба**\n**1. Дефиниции**\n* **Механична болка в гърба**: Това е болка, която произтича от конкретна структура в гръбначния стълб. Тя обхваща гръбначните тела, междупрешленните дискове, сакроилиачните стави и гръбначните връзки. Може да бъде причинена и от параспиналните мускули, твърдата мозъчна обвивка, гръбначния мозок или нервите.\n* **Възпалителна болка в гърба**: Разглежда се по-скоро като симптомокомплекс, отколкото като отделно състояние. Тя сигнализира за възпаление на самите прешлени, ставите на гръбначния стълб и ентезите — местата, където сухожилията и връзките се прикрепват към костите. **2. Характеристики на възпалителната болка**\n* **Възраст на настъпване**: Обикновено засяга пациенти под **40 години**.\n* **Начало**: Развива се **коварно** и подмолно; рядко започва остро.\n* **Ефект от активност**: Болката **се подобрява** значително при упражнения и движение.\n* **Ефект от покой**: Болката **не се подобрява** при почивка.\n* **Сутрешна скованост**: Продължава **над 30 минути**. **3. Характеристики на механичната болка**\n* **Възраст на настъпване**: Може да се появи на **всяка възраст**.\n* **Начало**: Променливо начало, като често може да започне **остро**.\n* **Ефект от активност**: Болката често **се влошава** при движение.\n* **Ефект от покой**: Състоянието често **се подобрява** при почивка.\" id=\"note-1772035457069-0\">Възпалителна болка в кръста</span>:</strong>&nbsp;</li><ul><li>Това е най-честият ранен симптом. Болката е с продължителност <strong>над 3 месеца</strong> и се среща предимно при <strong>мъже под 45-годишна възраст</strong>.</li><li>Характеризира се с внезапно начало и <strong>поява през нощта</strong>. Типично е <strong>подобрението при движение</strong> и изразеното <strong>влошаване в покой</strong>.</li><li>Болката често ирадиира към сакроилиачните стави, глутеалната област и бедрата. В началото може да бъде едностранна и непостоянна.</li></ul><li><strong>Сутрешна скованост:</strong> Болните изпитват силна скованост в гръбнака, която продължава <strong>около или над 30 минути</strong>.</li></ul><h3>2. Основни функционални тестове:</h3><ul><li><strong>Тест на Schober (Шобер):</strong> Използва се за оценка на подвижността на лумбалния гръбнак като ще се открие&nbsp;<strong>намалената предна флексия</strong> (навеждане напред).</li><li><strong>Симптом на Ott (От):</strong> Служи за доказване на <strong>ограничената подвижност на торакалния </strong>отдел.</li><li><strong>Симптом на Hirtz (Хирц):</strong> Показва засягане на <strong>костовертебралните стави</strong>, което ограничава разширяването на гръдния кош.</li><li><strong>Симптом на Forestier (Форестие):</strong> При навеждане на пациента встрани се наблюдава контрактура на параспиналната мускулатура, която се опъва <strong>„като струна на лък“</strong>.</li></ul><h3>3. Находки при оглед и движение:</h3><ul><li><strong>Ограничена обща подвижност:</strong> Установява се при опити за <strong>хиперекстензия</strong> (извиване назад), <strong>латерална флексия</strong> (навеждане встрани) или <strong>ротация</strong> (извъртане) на гръбначния стълб.</li><li><strong>Деформация на гръдния кош:</strong> Гръдният кош се описва като <strong>плосък</strong> вследствие на ставните изменения и ограничената дихателна екскурзия.</li></ul><h3>4. Ставно и ентезопатно засягане</h3><ul><li><strong>Сакроилеит:</strong> Възпалението на ставите между таза и гръбнака се установява чрез <strong>силна болка при директен натиск</strong> върху тях или при натиск върху тазовите кости (спини илиаци и сакрум).</li><li><strong>Ентезопатия:</strong> Болестта причинява болка при палпация на местата, където сухожилията се залавят за костите – най-вече при <strong>ахилесовите сухожилия, петите (плантарна фасция)</strong>, таза и коленете.</li><li><strong>Периферен артрит:</strong> Обикновено е <strong>асиметричен</strong> и засяга най-често долните крайници. Засягането на <strong>тазобедрените и раменните стави</strong> е агресивно и води до стесняване на ставната цепка, ерозии и трайни контрактури.</li></ul><h3>4. Извънскелетни (висцерални) прояви</h3><ul><li><strong>Остър преден увеит:</strong> Среща се при <strong>25-30% от болните</strong>. Проявява се едностранно, внезапно с болка, сълзене, фотофобия и намалено зрение. Рецидивите водят до образуване на предни (ирисът залепва за роговицата) и задни синехии (ирисът залепва за лещата), които могат да доведат до като <strong>катаракта,&nbsp;</strong><strong>оток на макулата </strong>и <strong>повишено вътреочно налягане.</strong></li><li><strong>Сърдечно-съдови:</strong> Развитие на аортна инсуфициенция, <strong>проводни нарушения </strong>(AV блок) и <strong>аортит на асцедентната аорта</strong>.</li><li><strong>Бели дробове:&nbsp;</strong><strong>Р</strong><p><strong>естриктивен тип </strong>белодробно заболяване, поради б</p>авно прогресираща <strong>двустранна върхова фиброза</strong> с кистозни изменения.</li><li><strong>Неврологични:</strong> <p>Най-често сс дължат на спинални фрактури и дислокации, атланто-аксиална сублукация, синдром на cauda equina.</p>&nbsp;</li><li><strong>Гастроинтестинални</strong>:&nbsp;<p>При две трети от болните хистологично с с</p><p>установява субклинично <strong>IBD, </strong>най-често <strong>болестта на Cohn </strong>и <strong>улцерозния колит</strong>.</p></li><li><strong>Бъбречни</strong>:&nbsp;<p><strong>Амилондозата </strong>на бъбреците е вторична и е сравнително рядко усложнение на АС. Причинява протеинурия и напредваща ХБН. Рядко срещаната IgA-нефропатия клинично се проявява </p><p>с хематурия.</p></li><li><p><strong>Анемия</strong>.</p></li></ul><h3>5. Клинични форми на АС</h3><ul><li><strong>Централна форма:</strong> <p>Ангажиране само на гръбнака и сакроилиачните стави със </p>спондилартрит и сакроилеит.</li><li><strong>Ризомиелична форма:</strong> Сакроилеит и засягане на раменни и тазобедрени стави.</li><li><strong>Гръбначно-периферна форма:</strong> Спондилартрит и периферен артрит.</li><li><strong><u>Скандинавска форма</u>:</strong> Сакроилеит и засягане на малките стави на ръцете. Тука се прави диференциална диагноза с ревматоидния артрит.</li><li><strong>Висцерална форма:</strong> Със засягане на сърцето, белите дробове, бъбреците и предния очен сегмент.</li></ul><hr><h2>Изследвания:</h2><p>Няма лабораторен тест, който да е напълно специфичен за Анкилозиращия спондилит. Диагнозата се гради върху комбинация от клинични, лабораторни и образни данни.</p><h3>1. Лабораторни и генетични изследвания</h3><ul><li><strong>Маркери на възпаление:</strong> Установяват се ускорена <strong>СУЕ</strong> и повишен <strong>CRP</strong>.</li><li><strong>Генетичен тест:</strong> Над <strong>90% от болните са HLA-B27 положителни</strong>.</li><li><strong>Други:</strong> Повишени стойности на <strong>IgA</strong> и възможна средностепенна анемия.</li></ul><h3>2. Радиографски находки (Рентгенография и ЯМР)</h3><p>Образните изследвания проследяват прогресията от ранно възпаление до пълна анкилоза:</p><ul><li><strong>Romanus лезии:</strong> Поява на триъгълни участъци на склероза в ъглите на прешленните тела (<strong>shiny corner sign</strong>), резултат от възпаление.</li><li><strong>Синдесмофити:</strong> <p>Повърхностните слоеве на фиброзния пръстен осифицират, образувайки интервертебрални костни мостове</p>, които прогресират от лумбалните към цервикалните прешлени.</li><li><strong>„Бамбукова пръчка“:</strong> <p>Краен стадий, при който настъпва пълно спояване на прешлените поради анкилоза на апофизните стави и осификация на надлъжните лигаменти.</p></li><li><p><strong>Остеопороза:</strong> Анкилозата задължително се съпътства от развитие на <strong>тежка остеопороза</strong>.</p><br></li><li><p><strong>Периферни промени:</strong> Рентгенологично се установява <strong>двустранен симетричен сакроилеит</strong>, костни ерозии и остеит на местата на залавяне на сухожилията (тибиални туберози, крила на илиачните кости, трохантери, калканеус).</p><br></li><li><strong>ЯМР:</strong> Златен стандарт за ранна диагноза чрез откриване на <strong>костно-мозъчен </strong><strong>оток </strong>около сакроилеачните стави.</li></ul><hr><h2>Диференциална диагноза</h2><p>АС трябва да се различава от:</p><ul><li>Анкилозираща хиперостоза на Forestier (<strong>DISH синдром</strong>);</li><li>Септичен сакроилеит или септичен дисцит;</li><li>Туберкулозен спондилит;</li><li>Хипопаратиреоидизъм;</li><li>Кондензиращ остеит на илиачните кости;</li><li>Вродена кифосколиоза.</li></ul><hr><h2>Диагностични критерии</h2><p>В съвременната ревматология се използват два основни набора от критерии, които позволяват както ранно откриване на заболяването, така и класифициране на напредналите форми.</p><h3>1. ASAS критерии (за ранен аксиален спондилоартрит)</h3><p>Тези критерии се прилагат при пациенти с болка в гърба ≥ 3 месеца и възраст на започване &lt; 45 години. Те са по-съвременни, защото позволяват поставяне на диагноза чрез ЯМР още преди появата на рентгенови промени.</p><p><strong>Диагноза се поставя при един от двата пътя:</strong></p><ul><li><strong>Образен път:</strong> Сакроилеит от образно изследване* <strong>+</strong> <p>≥</p> 1 SpA белег#.</li><li><strong>Генетичен път:</strong> Положителен HLA-B27 <strong>+</strong> <p>≥</p> 2 други SpA белези#.</li></ul><p><strong># Специфични SpA белези:</strong></p><ul><li>Възпалителна болка в гърба.</li><li>Артрит, Ентезит (пета) или Дактилит.</li><li>Увеит, Псориазис или IBD.</li><li>Добър отговор към НПВС.</li><li>Фамилна анамнеза за SpA.</li><li>Положителен HLA-B27 или увеличен CRP.</li></ul><h3>2. Ревизирани Нюйоркски критерии (за дефинитивен АС)</h3><p>Използват се за потвърждаване на структурно напреднал Анкилозиращ спондилит (използвани и днес). Диагнозата е сигурна при наличие на <strong>един рентгенологичен + поне един клиничен критерий</strong>:</p><p><strong>Клинични критерии:</strong></p><ul><li><strong>Болка и скованост</strong> в лумбалната област за поне 3 месеца, която намалява при движение и не се повлиява от покой (типична нощна болка).</li><li><strong>Ограничена подвижност</strong> на лумбалния гръбнак в сагитална и фронтална равнина (най-рано се ограничава дорзалната флексия).</li><li><strong>Намалена подвижност на гръдния кош</strong> под нормалните стойности за съответната възраст.</li></ul><p><strong>Рентгенологични критерии:</strong></p><ul><li><strong>Двустранен сакроилеит</strong> (II-IV стадий).</li><li><strong>Едностранен сакроилеит</strong> (III-IV стадий).</li><li>Откриването на <strong>вертикален синдесмофит</strong> във фас на лумбалния или торакалния гръбнак има подобна диагностична стойност.</li></ul><hr><h2>Лечение и профилактика</h2><p>Терапията на Анкилозиращия спондилит цели <strong>овладяване на възпалителната активност</strong>, поддържане на <strong>обема на движение</strong> и спиране на рентгенографската прогресия на заболяването.</p><h3>1. Немедикаментозно лечение и режим</h3><ul><li><strong>Режим и диета:</strong> Свободен режим, но със строга <strong>забрана на тютюнопушенето</strong>.</li><li><strong>Физикална терапия:</strong> Ежедневна <strong>лечебна физкултура </strong>е критично важна, тъй като заболяването показва изразено подобрение от упражнения. Включва още физиолечение, хидротерапия и <strong>плуване</strong>.</li><li><strong>Балнеолечение:</strong> Прилага се само в неактивен стадий на заболяването.</li></ul><h3>2. Медикаментозно (Патогенетично) лечение</h3><h4>А. Нестероидни противовъзпалителни средства (НСПВС)</h4><ul><li><strong>Приложение:</strong> Използват се при аксиално и периферно ангажиране.</li><li><strong>Ефект:</strong> Установено е, че продължителната им употреба <strong>забавя рентгенографската прогресия</strong> и образуването на синдесмофити.</li></ul><h4>Б. Глюкокортикостероиди (ГКС)</h4><ul><li><strong>Локално приложение:</strong> Използват се при периферен артрит и ентезит.</li><li><strong>Системно приложение:</strong> Прилагат се само за <strong>кратки курсове при обостряне</strong> (перорално или парентерално). <strong>Не се препоръчват за дългосрочно системно лечение.</strong></li></ul><h4>В. Болестопроменящи антиревматични средства (БПАРС)</h4><ul><li><strong>Sulfasalazine (Salazopyrin):</strong> Таблетки по 500 мг (дневна доза <strong>2.0 гр.</strong>). </li><li><strong>Индикации:</strong> Притежава значителен ефект при ранен АС и по-изразен ефект върху <strong>периферните стави</strong>.</li></ul><h4>Г. Биологични медикаменти</h4><p>Показани са при персистираща висока активност и липса на ефект от конвенционалното лечение.</p><p><strong>1. TNF-α блокиращи средства (Anti-TNF):</strong></p><ul><li><strong>Infliximab:</strong> Венозно, 5 мг/кг на седмица 0, 2, 6 и след това на всеки 8 седмици.</li><li><strong>Etanercept (Enbrel):</strong> Субкутанно, <strong>50 мг/седмично</strong>. Доказано повлиява възпалението на СИС и гръбнака чрез ЯМР.</li><li><strong>Adalimumab (Humira):</strong> Субкутанно, <strong>40 мг на 2 седмици</strong>. Добър ефект на 12-ата седмица.</li><li><strong>Golimumab</strong> и <strong>Certolizumab</strong>.</li></ul><p><strong>2. Инхибитори на Интерлевкин 17А (Anti-IL 17A):</strong></p><ul><li><strong>Secukinumab (Cosentyx):</strong> Нов клас с бърз начален ефект. </li><li><strong>Важно:</strong> Противопоказани при наличие на съпътстващо възпалително чревно заболяване (IBD).</li></ul><h3>3. Лечение на усложненията</h3><ul><li><strong>Остеопороза:</strong> Стандартна антиостеопорозна терапия.</li><li><strong>Остър увеит:</strong> Локално с ГКС капки/инжекции и мидриатици (за предотвратяване на синехии). Повечето TNF-блокери (без Етанерцепт) действат добре върху увеита.</li></ul><h3>4. Хирургично лечение</h3><p>Налага се при тежки деформации или органни увреждания:</p><ul><li><strong>Ендопротезиране:</strong> На тазобедрена става при тежък коксит.</li><li><strong>Остеотомия:</strong> На интервертебрални мостове.</li><li><strong>Сърдечни операции:</strong> Протезиране на аортна клапа или имплантиране на пейсмейкър при тежки проводни нарушения.</li><li><strong>Неврохирургия:</strong> При фрактури на гръбначния стълб.</li></ul><h3>Трудоспособност</h3><p>При голяма част от болните трудоспособността е <strong>запазена</strong>, стига да няма тежки висцерални увреждания и да се упражнява подходяща професия.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><h1 style=\"text-align: center\">Тема 42:&nbsp;Ревматоиден артрит – етиология, патогенеза, клиника и диагноза</h1><h2 style=\"text-align: left\">Определение</h2><p><strong>Ревматоидният артрит (РА)</strong> е хронично мултисистемно автоимунно заболяване, чиято основна проява е <strong>симетричният погресиращ </strong><strong>ерозивен артрит на малките и средни по размер стави</strong>. Заболяването има системен характер и може да засегне също големи стави, както и различни вътрешни органи (<strong>бели дробове, сърце</strong>), кръвоносни съдове и кръвотворната система.</p><p>РА е най-често срещаното заболяване сред възпалителните ставни заболявания, като засяга средно <strong>1% от населението</strong>. Наблюдава се подчертано превалиране при жените, при които честотата е от <strong>2 до 4 пъти по-висока</strong> в сравнение с мъжете.</p><hr><h2></h2><h2>Епидемиология в България</h2><p>Ревматоидният артрит засяга значителна част от населението в страната, като статистическите данни сочат следното:</p><ul><li>Заболели са <strong>около 60 000 – 70 000 души</strong> от активното население.</li><li>Наблюдава се ясно изразен полов диморфизъм: приблизително <strong>75% са жени</strong> (във възрастта между 35 и 50 г.), докато останалите <strong>25% са мъже</strong> (между 40 и 60-годишна възраст).</li><li>Психологическият аспект е значим – <strong>50% от пациентите</strong> погрешно смятат, че за тяхното състояние не може да се направи нищо.</li></ul><hr><h2>Етиология</h2><p>Точната причина за възникването на ревматоидния артрит остава <strong>неизвестна</strong>. Заболяването се определя като <strong>идиопатичен автоимунен процес</strong>. Редица фактори допринасят за неговото развитие:</p><ul><li>Наличие на <strong>„възприемчиви“ гени</strong>, като най-значимият е <strong>HLA-DRβ1*4</strong>.</li></ul><ul><li>Наличие на специфични <strong>болест-предизвикващи имунни клетки</strong>.</li><li>Действие на <strong>цитокини и мрежи на сигнална трансдукция</strong>, които стимулират и поддържат хроничното възпаление.</li></ul><ul><li>Подозира се ролята на различни <strong>инфекциозни причинители</strong> като отключващ фактор на имунния отговор.</li></ul><hr><h2>Патогенеза</h2><p>Патогенетичният процес при РА е сложен и преминава през <strong>пет основни фази</strong>:</p><ol><li>Начална</li><li>Медиаторна</li><li>Лимфоидна</li><li>Агресивна</li><li>Деструктивна</li></ol><p>Ключово значение за развитието на болестта има <strong>взаимодействието на антиген-представящите клетки със CD4-позитивните Т-лимфоцити</strong>.</p><h3>Възпалителна каскада</h3><p>Активирането на Т-клетките отключва серия от междуклетъчни реакции, при които лимфоцитите и макрофагите освобождават <strong>проинфламаторни цитокини, </strong>които от своя страна индуцират синовиална пролиферация и освобождаване на деструктивни ензими.</p><p>Централна роля в тази низходяща верига от събития играе <strong>TNFα.</strong></p><h3>Роля на цитокините:</h3><p>Служат като естествени регулатори на клетъчната функция, индуцират продукцията на други цитокини и регулират възпалението, като се свързват с рецепторите по клетъчната повърхност или предотвратяват клетъчното активиране.</p><h3>Функции на TNFα в ставната деструкция</h3><p>TNFα действа по три основни пътя:</p><ul><li><strong>Чрез остеокластите:</strong> Стимулира костната резорбция, което води до образуване на <strong>костни ерозии</strong>.</li><li><strong>Чрез синовиоцитите:</strong> Поддържа ставната инфламация, проявяваща се с <strong>болка и отоци</strong>.</li><li><strong>Чрез хондроцитите:</strong> Предизвиква деградация на хрущяла, което води до <strong>стесняване на ставното пространство</strong>.</li></ul><hr><h2>Патоморфологични промени</h2><p>Патоморфологичната картина се характеризира с развитието на <strong>хроничен синовит</strong> и формиране на <strong>панус</strong>.</p><h3>Промени в синовиалната мембрана</h3><p>Налице е изразена <strong>хипертрофия и хиперплазия</strong> на синовиалната мембрана. Тя е масивно инфилтрирана от лимфоцити, плазматични клетки и макрофаги. Нараства количеството на <strong>ставната течност</strong>, освобождават се <strong>провъзпалителни цитокини</strong>, активира се <strong>каскадата на възпалението</strong>.</p><h3>Образуване на панус (Pannus)</h3><p>Експанзията на синовиалната мембрана формира т.нар. <strong>панус</strong>. Синовиалните клетки и хондроцитите освобождават <strong>деструктивни ензими</strong>, които:</p><ul><li>Лизират ставния хрущял.</li><li>Водят до <strong>костни ерозии</strong> и ставна нестабилност.</li><li><p>Между увредените ставни повърхности </p><p>може да се достигне до <strong>фиброзна </strong></p><p><strong>анкилоза</strong>.</p></li><li><p>Възпалителният процес обхваща и</p><p>периставните структори. </p>Предизвикват фиброза на ставната капсула и увреждане на сухожилията, бурсите и мускулите.</li></ul><h3>Ревматоидни възли</h3><p>Те са <strong>патогномонични</strong> за заболяването и представляват подкожно разположени грануломи. Установяват се при 20% от болните. Структурата на ревматоидния възел включва:</p><ol><li><strong>Централна зона:</strong> Фибриноидна некроза.</li><li><strong>Междинна зона:</strong> Радиално разположени продълговати съединителнотъканни клетки.</li><li><strong>Периферия:</strong> Хронична грануломатозна тъкан.</li></ol><p>Подобни грануломи могат да се наблюдават и в миокарда, перикарда, ендокарда и сърдечните клапи, висцералната плевра, белите дробове, склерите, твърдата мозъчна обвивка, слезката, ларингса както и в синовиалната мембрана, периставните структури и сухожилията.</p><hr><h2></h2><h2>Клинична картина</h2><h3>Общи и начални прояви</h3><p>Клиничната картина на ревматоидния артрит обикновено се развива постепенно в продължение на седмици или месеци. </p><ul><li><strong>Общи симптоми:</strong> Болните често се оплакват от <strong>отпадналост, лесна умора, безапетитие, редукция на тегло</strong> и повишаване на температурата до субфебрилна.</li><li><strong>Сутрешна скованост:</strong> Това е един от най-характерните ранни белези. Продължава <strong>над 30 минути</strong>, а често трае с часове.</li><li><strong>Характер на артрита:</strong> Протича като <strong>симетричен полиартрит</strong>, ангажиращ предимно малките стави. Налице е болка, оток и топлина.&nbsp;<p>Постепенно начало в повечето случаи като протича</p><p> в продължение на седмици до месеци.</p></li></ul><h3>Клинични стадии на протичане</h3><p>Заболяването преминава през три основни стадия, които отразяват прогресията на ставната деструкция:</p><p><strong>1. Ранен стадий</strong></p><ul><li>Характеризира се с наличие на <strong>синовит</strong> и оток на&nbsp;&nbsp;<strong>проксималните интерфалангеални (ПИФ)</strong> и <strong>метакарпофалангеални (МКФ) стави</strong>.</li><li>Обективно се наблюдава <strong>вретеновиден оток</strong> на меките тъкани.</li><li><p>Налице е минимална ставна увреда и лека загуба на функция.</p><br></li></ul><p><strong>2. Установен стадий</strong></p><ul><li>Наблюдава се <strong>персистиращ синовит</strong> и започват да се оформят първите деформации.</li><li>Установяват се изявени рентгенови ставни увреди, <strong>костни ерозии</strong> и деструкция на хрущяла.</li><li><p>Пациентите имат умерена до тежка функционална инвалидизация.</p><br></li></ul><p><strong>3. Късен стадий</strong></p><ul><li>Бележи се от <strong>тежка ставна деструкция</strong> и чести обостряния на процеса, както и повишена честота на болестност и смъртност.</li><li>Налице са тежки деформации, <strong>улнарна девиация</strong>,&nbsp;<strong>остеопения </strong>и изразено <strong>стесняване на ставното пространство</strong>.</li><li><p>Висока степен на нетрудоспособност, която често налага извършването на <strong>тотална артропластика</strong>.</p><br></li></ul><h3>Прогресия на костни ерозии:</h3><ul><li>Костни ерозии настъпват рано при РА. Развиват се при 63.6% от пациентите за период от 3 години.</li><li><u>Ерозии могат да установят на MRI в рамките на 4 месеца от началото на РА</u>.</li><li>Скоростта на прогресия е сигнификантно по-висока през първата, отколкото през втората и третата година.</li></ul><h3>Засягане на тазобедрени и раменни стави</h3><p>Ангажирането на <strong>тазобедрените стави и раменните стави</strong> при ревматоиден артрит се наблюдава сравнително <strong>рядко</strong>. Тези стави обикновено се засягат в по-напредналите фази на болестния процес. Характерната <strong>загуба на диапазон на подвижност</strong> в тях е клиничен белег, който се установява типично в <strong>късния стадий</strong> на заболяването.</p><h3>Специфични деформации на крайниците</h3><p>Вследствие на хроничния синовит, разрушаването на ставните повърхности и мускулната атрофия, се оформят няколко характерни типа деформации:</p><ul><li><strong>М-тип:</strong> При тази деформация е <strong>нарушен юмручният захват</strong>.</li><li><strong>Тип „Лебедова шия“:</strong> Силно инвалидизираща форма, при която са <strong>нарушени юмручният, върховият и кукестият захват</strong>.</li><li><strong>Тип „ULNARна девиация“:</strong> Дължи се на патологични изменения в <strong>mm. interossei palmares et dorsales</strong>. Ръката се отклонява трайно в <strong>улнарна посока</strong> (към малкия пръст).</li><li><strong>Тип „Ретрахирана ръка“:</strong> Наблюдава се при пълно <strong>разрушаване на ставните плоскости</strong>.</li><li><strong>Тип „Двугърба камила“:</strong> Резултат от развила се <strong>сублуксация в радио-карпалната става</strong>, съчетана с изразена <strong>атрофия на тъканите на гърба на ръката</strong>.</li><li><strong>Тип „Ревматоидно стъпало“:</strong> Характеризира се с <strong>контрактура на флексорите на пръстите</strong>, при което се оформят т.нар. <strong>„птичи пръсти“</strong>.</li></ul><h3>Ревматоиден васкулит</h3><p><strong>Ревматоидният васкулит</strong> се определя като едно от <strong>най-сериозните извънставни усложнения</strong> на заболяването. Неговото наличие е белег за системно ангажиране на организма.</p><ul><li><strong>Кожни прояви:</strong> Могат да се наблюдават <strong>улцерации&nbsp;</strong>или специфичен еритемен обрив.</li><li><strong>Органно засягане:</strong> Процесът може да обхване <strong>серозни обвивки, бели дробове, сърце (коронарни съдове)</strong> и <strong>нервна система</strong>.</li></ul><h3>Извънставни прояви и системно засягане</h3><p>Ревматоидният артрит е <strong>системно заболяване</strong>, при което степента на системното засягане е <strong>главен определящ фактор за преживяемостта</strong> на пациента.</p><ul><li><strong>Сърдечно-съдова система:</strong> Свързва се с <strong>повишен сърдечно-съдов риск</strong>. <strong>Клапен сърдечен порок</strong> се оформя при <strong>2 – 3% от болните</strong> (след изключване на прекаран ревматизъм). Могат да се развият <strong>преходен миокардит или перикардит</strong>, които рядко дават явни клинични признаци.</li><li><strong>Бъбреци:</strong> При висока активност на болестта може да се развие мембранозен или мембранозно-пролиферативен <strong>гломерулонефрит</strong>. <strong>Най-тежкото бъбречно увреждане е амилоидозата</strong>, която обикновено се проявява след <strong>7 – 10 годишна давност</strong> на артрита (проява на хроничният характер на заболяването).</li><li><strong>Очи:</strong> Засягането протича под формата на <strong>склерит, еписклерит или склеромалация</strong>. В съчетание със синдрома на Sjogren се развива <strong>сух кератоконюнктивит</strong>.</li><li><strong>Други системи:</strong> Наблюдават се <strong>белодробни увреждания</strong> и развитие на <strong>остеопороза</strong>. При част от болните могат да се установят <strong>увеличени лимфни възли и слезка</strong>.</li></ul><h3>Синдром на Фелти</h3><p><strong>Синдромът на Фелти</strong> представлява особена форма на ревматоиден артрит, която протича изключително тежко. За него е характерна следната <strong>клинична триада</strong>:</p><ol><li><strong>Ревматоиден артрит.</strong></li><li><strong>Спленомегалия</strong>.</li><li><strong>Левкопения</strong>.</li></ol><p>В голяма част от случаите се наблюдава и <strong>тромбоцитопения</strong>. Съществува висок <strong>риск от усложнения</strong>, най-често <strong>тежки инфекции</strong> и <strong>трудно зарастващи рани по крайниците</strong>.</p><hr><h2>Лабораторна находка</h2><p>При лабораторното изследване на пациенти с ревматоиден артрит се наблюдават специфични промени в кръвната картина и показателите за възпаление:</p><ul><li><strong>Броят на левкоцитите</strong> обикновено е <strong>нормален или леко повишен</strong>. Важно изключение е <strong>синдромът на Felty</strong>, при който се установяват <strong>левкопения и спленомегалия</strong>.</li><li>При <strong>1/3 от болните</strong> се открива <strong>умерено изразена анемия</strong>.</li><li>За оценка на възпалителната активност се използват два основни показателя: <strong>CRP</strong>, който е <strong>най-информативен</strong>, и <strong>СУЕ</strong>, който е най-достъпен в клиничната практика.</li><li><strong>Ревматоидният фактор </strong>е положителен при <strong>75% от болните</strong>.</li><li><strong>Анти-ССР антителата</strong> са позитивни при <strong>над 95%</strong> от пациентите и се определят като <strong>ранен маркер</strong> за заболяването.</li></ul><h3>Антитела: Ревматоиден фактор (РФ)</h3><p>Ревматоидният фактор представлява антитела, които са насочени срещу <strong>Fc фрагмента на нормалните IgG</strong>.</p><ul><li><strong>Видове:</strong> Най-често се срещат от клас <strong>IgM</strong>, но могат да бъдат също от класовете IgG, IgA и IgE.</li><li><strong>Специфичност:</strong> Те са <strong>неспецифични за РА</strong>, тъй като могат да се наблюдават и при инфекции, системни заболявания, автоимунни феномени и злокачествени заболявания.</li><li><strong>Честота:</strong> Установяват се при <strong>75 до 80%</strong> от пациентите по някое време в хода на болестта. Като нормална находка (без наличие на болест) се срещат в 1-4% от популацията и до <strong>10-25% при лица над 70-годишна възраст</strong>.</li><li><strong>Клинично значение:</strong> Наличието на РФ (<strong>серопозитивност</strong>) се свързва с <strong>агресивна форма на болестта</strong> и по-чести усложнения като <strong>ревматоидни възли и васкулит</strong>. Важно е да се отбележи, че наличието на ревматоидни възли може да предшества клиничното развитие на артрита.</li></ul><h3>Антитела: ACPA (или ACCP)</h3><p><strong>ACPA (Anti-cyclic citrullinated peptide antibody)</strong> са нова група антитела, които играят критична роля в съвременната диагностика.</p><ul><li><strong>Специфичност:</strong> Те притежават <strong>висока специфичност</strong> за разграничаване на РА от други ревматични заболявания.</li><li><strong>Прогностична стойност:</strong> ACPA имат <strong>висока прогностична стойност</strong> за бъдещо развитие на РА както при здрави индивиди, така и при пациенти с недиференциран артрит.</li><li><strong>Връзка с деструкцията:</strong> Наличието на <strong>anti-CCP антитела</strong> е свързано с по-изразена <strong>рентгенова прогресия</strong> на заболяването.</li></ul><p>В диагностичния панел се включват и следните <strong>автоантитела</strong>:</p><ul><li>Анти-цикличен цитрулиниран протеин (<strong>анти-ССР</strong>).</li><li>Анти-мутирал цитрулиниран виментин антитела (<strong>анти-МСV</strong>).</li><li>Анти-кератинови антитела (<strong>АКА</strong>).</li><li>Анти-филагрин антитела (<strong>АFА</strong>).</li><li>Анти-перинуклеарни антитела (<strong>АPА</strong>).</li></ul><hr><h2>Рентгенова находка</h2><p>В зависимост от еволюцията на патологичните промени в ставите, ревматоидният артрит се разделя на <strong>четири рентгено-анатомични стадия</strong>:</p><ul><li><strong>І стадий:</strong> Характеризира се с <strong>юкстаартикуларна остеопороза</strong>.</li><li><strong>ІІ стадий:</strong> Наблюдава се <strong>леко стеснение на ставната междина</strong> и наличие на <strong>единични костни ерозии</strong>.</li><li><strong>ІІІ стадий:</strong> Установява се <strong>изразено стеснение на ставната междина</strong> и <strong>множество ерозии</strong>.</li><li><strong>ІV стадий:</strong> Включва всички промени от трети стадий, съпроводени с <strong>фиброзна или костна анкилоза</strong>.</li></ul><hr><h2>1987 ACR класификационни критерии за РА</h2><p>Тези критерии се използват за оценка на еволюцията на заболяването. Диагнозата се поставя, ако са изпълнени <strong>поне 4 от следните критерии</strong>:</p><ol><li><strong>Сутрешна скованост</strong> с продължителност <strong>над 1 час</strong>.</li><li><strong>Оток на 3 или повече стави</strong>.</li><li><strong>Оток на стави на ръцете</strong>.</li><li><strong>Симетрично</strong> ставно засягане.</li><li><strong>Рентгенови промени</strong> (ерозия или костна деминерализация).</li><li>Наличие на <strong>ревматоидни възли</strong>.</li><li>Положителен <strong>Ревматоиден фактор (RF+)</strong> в серума.</li></ol><p>*За критериите от 1 до 4 се изисква давност на оплакванията от <strong>поне 6 седмици</strong>.</p><h2><hr><p>2010 ACR/EULAR Класификационни критерии за РА</p></h2><p>Тези критерии се базират на точкуване по алгоритъм на наличните находки, дефинирани в 4 основни категории. За да се постави сигурна диагноза, са необходими <strong>≥ 6 от 10 възможни точки</strong>.</p><h3>Ставно ангажиране</h3><p><em>Ставното ангажиране се отчита при наличие на оточни или болезнени стави (наличието на синовит може да бъде установено и с образна методика). Дисталните интерфалангеални стави, първата карпо-метакарпална става и първата метатарзофалангеална става са изключени от оценка.</em></p><ul><li>1 голяма става = <strong>0 точки</strong></li><li>2-10 големи стави = <strong>1 точка</strong></li><li>1-3 малки стави (със или без засягане на големи стави) = <strong>2 точки</strong></li><li>4-10 малки стави (със или без засягане на големи стави) = <strong>3 точки</strong></li><li>&gt; 10 стави (поне 1 от които е малка става) = <strong>5 точки</strong></li></ul><h3>Серология</h3><p><em>Необходим е поне един резултат от лабораторно изследване.</em></p><ul><li>Негативен тест за ревматоиден фактор (РФ) <strong>И</strong> негативни ACPA = <strong>0 точки</strong></li><li>Позитивен тест за РФ <strong>ИЛИ</strong> ACPA в <em>нисък титър</em> (≤ 3 пъти над горната граница на нормата) = <strong>2 точки</strong></li><li>Позитивен тест за РФ <strong>ИЛИ</strong> ACPA във <em>висок титър</em> (&gt; 3 пъти над горната граница на нормата) = <strong>3 точки</strong></li></ul><h3>Острофазови показатели</h3><p><em>Необходим е поне един резултат от лабораторно изследване.</em></p><ul><li>Нормални стойности на CRP <strong>И</strong> СУЕ = <strong>0 точки</strong></li><li>Повишени стойности на CRP <strong>ИЛИ</strong> ускорено СУЕ = <strong>1 точка</strong></li></ul><h3>Продължителност на симптомите</h3><ul><li>&lt; 6 седмици = <strong>0 точки</strong></li><li>≥ 6 седмици = <strong>1 точка</strong></li></ul><h2><hr>Диагностични критезии на ACR</h2><p>Първите 4 критерия трябва да са били налице поне 6 седмици. Диагнозата РА се поставя, ако са налице най-малко 4 от 7-те критерия.</p><ol><li><strong>Сутрешна скованост</strong> във или около ставите, продължаваща поне един час преди максималното подобрение.</li><li><strong>Артрит в три или повече ставни зони,</strong> установени от лекар. Посочват се 14 възможни ставни зони (вдясно и вляво) - проксимални интерфалангеални стави, метакарпофалангеални стави, китка, лакът, коляно, глезен, метатарзофалангеални стави.</li><li><strong>Артрит на стави на ръцете</strong> (китки, метакарпофалангеални или проксимални интерфалангеални стави).</li><li><strong>Симетричен артрит</strong> (едновременно засягане на едни и същи ставни зони двустранно). Не се изисква абсолютна симетрия при засягане на проксималните интерфалангеални, метакарпофалангеалните или метатарзофалангеалните стави.</li><li><strong>Ревматоидни възли</strong>, установени от лекар.</li><li><strong>Ревматоиден фактор в серума</strong>. Установяване на повишено количество на ревматоиден фактор в серума с метод, който е положителен при по-малко от 5% при здрави лица.</li><li><strong>Рентгенови промени</strong>. Наличие на типични за РА рентгенови промени при рентгенография на ръце и китки - костни ерозии, остеопороза.</li></ol><p>След диагностицирането е необходимо да се направи комплексна клинична оценка на РА при конкретния болен. Тя включва определяне на степента на възпалителната активност, варианта на протичане (бенигнен, агресивен), функционалния клас и т.н.</p><hr><h2>Ранна диагноза на РА</h2><p>Ранното разпознаване на заболяването е от изключително значение за неговия изход, но съществуват редица <strong>бариери</strong>, които го затрудняват. Те включват:</p><ul><li>Закъснение в търсенето на медицинска помощ от страна на пациентите.</li><li>Закъсняла ориентация на общопрактикуващите лекари към диагнозата.</li><li>Забавяне на консултацията с ревматолог или пълна липса на специализиран кабинет в съответния регион.</li></ul><p>Лекарят трябва да подозира наличието на ревматоиден артрит при наличие на следните клинични данни:</p><ul><li>Три или повече оточни стави.</li><li>Засягане на метакарпофалангеалните или метатарзофалангеалните стави, което се проявява с изявена болка при страничен обхват.</li><li>Сутрешна скованост с продължителност 30 или повече минути.</li></ul><hr><h2>Диференциална диагноза</h2><p>Ревматоидният артрит трябва да бъде разграничен от широк спектър други заболявания, протичащи със ставен синдром:</p><ol><li><strong>Серонегативни спондилартропатии: </strong>Болест на Бехтерев, псориатичен артрит, синдром на Reiter и артрити, развиващи се при хронични ентеропатии.</li><li><strong>Артрити, свързани с инфекция: </strong>Септичен артрит, реактивен артрит, ревматизъм и др.</li><li><strong>Системни заболявания на съединителната тъкан: </strong>Системен лупус еритематозус, системна склеродермия, полимиозит/дерматомиозит, системни васкулити, болест на Behcet и overlap-синдроми.</li><li><strong>Кристални артропатии: </strong>Подагра и хондрокалциноза.</li><li><strong>Остеоартроза.</strong></li><li><strong>Други заболявания: </strong>Саркоидоза, хемофилна артропатия, фибромиалгия, хемохроматоза, интермитентна хидрартроза и пигментен вилонодуларен синовит.</li></ol><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><h1></h1><h1 style=\"text-align: center\"><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\">Тема 43: Колагенози – дефиниция, имунопатогенеза, класификация и диагноза</h1><p>Нещо си</p><h1><div style=\"text-align: center\"></div><div style=\"text-align: center\"><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\">Тема 44: Ревматоиден артрит – принципи на лечение.</div></h1><h2>Обща характеристика:</h2><p>Лечението на ревматоидния артрит (РА) е <strong>симптоматично </strong>и <strong>патогенетично</strong>. То е продължително и комплексно.</p><h3>Основни цели на лечението:</h3><ul><li><strong>Облекчаване на болката</strong> и потискане на ставното възпаление.</li><li><strong>Предотвратяване</strong> на хрущялната и костната деструкция.</li><li><strong>Съхраняване на ставната функция</strong> и качеството на живот на болните.</li><li><strong>Овладяване на извънставните прояви</strong>, когато такива са налице.</li></ul><hr><h2>Стратегия и обхват на лечението</h2><p>Лечението трябва да започне <strong>рано</strong>, за да се спре ходът на болестта и да се предотврати разрушаването на ставите и инвалидизирането на болния. Терапията е комплексна и включва три основни направления:</p><h4>1. Нелекарствени методи</h4><ul><li><strong>Обучение на болния.</strong></li><li><strong>Физиотерапия.</strong></li><li><strong>Помощни средства:</strong> Канадки, патерици, проходилки (ако е необходимо за придвижването).</li></ul><h4>2. Лекарствени средства</h4><ul><li><strong>Нестероидни противовъзпалителни средства (НСПВС):</strong> Целят намаляване на болката и сковаността в засегнатите стави. Те обаче <strong>не могат</strong> да спрат хода на болестта.</li><li><strong>Болестопроменящи антиревматични средства (БПАРС):</strong> Насочени са към предотвратяване разрушаването на ставите.</li></ul><h4>3. Хирургични методи</h4><p>Използват се при напреднали деформации за възстановяване на функцията.</p><h2><hr>I. Нестероидни противовъзпалителни средства</h2><h3>Обща характеристика и цели на терапията</h3><p>НСПВС са най-често използваните медикаменти за лечение на ставни заболявания. Тяхното основно предназначение е постигането на значително клинично подобрение чрез:</p><ul><li>Намаляване на болката в засегнатите стави.</li><li>Повлияване на отока и сутрешната скованост.</li><li>Подобряване на функционалния капацитет на опорно-двигателния апарат.</li><li>Прилагат се до 14 дена.</li></ul><p>Важно е да се отбележи, че НСПВС водят само до симптоматично повлияване. Тези лекарствени продукти не променят естествения ход на болестта и не могат да спрат ставната деструкция.</p><h3>Механизъм на действие</h3><p>Основният механизъм на действие на НСПВС е инхибирането на простагландиновата синтеза. Това се постига чрез потискане на активността на ензима <span class=\"editor-note\" data-note=\"- **Физиологични функции на простагландините: ** - Простагландините участват активно в поддържането на хомеостазата, като тяхното потискане от конвенционалните НСПВС води до редица странични ефекти.\n- **Роля в стомашно-чревния тракт (СЧТ)** - В стомашно-чревния тракт макрофагите и епителните клетки синтезират **PGE2**, а мастоцитите произвеждат **PGD2**. Тези простагландини осигуряват защита на стомашната лигавица чрез следните механизми: - Предизвикват вазодилатация. - Понижават синтеза на солна киселина. - Повишават синтеза на карбонати и муцин, които изграждат защитната бариера на стомаха. - Осигуряват миорелаксация.\n- **Роля в отделителната система** - В бъбреците простагландините са отговорни за поддържането на бъбречния кръвоток и водно-солевия баланс: - **PGE2:** Предизвиква вазодилатация и дилатация на бъбречните съдове. - **PGI2:** Оказва вазодилатиращо действие и притежава антиагрегантен ефект върху съдовия ендотел. - Участват в регулирането на електролитите чрез повишаване на тубулната реабсорбция на натрий. Ензимът циклооксигеназа съществува под формата на два основни изоензима, които имат различна биологична роля:\n- **СОХ-1:** Това е физиологичният ензим, който отговаря за поддържането на хомеостазата в организма.\n- **СОХ-2:** Това е индуцируемият ензим, който поддържа възпалителната реакция в тъканите.\" id=\"note-1771959910789-0\">циклооксигеназа</span> (COX). Въпреки че простагландините са ключови медиатори за поддържане на възпалението, те изпълняват и жизненоважни физиологични функции в организма.</p><p>Конвенционалните (старите) НСПВС инхибират и двата изоензима безразборно. Потискането на COX-1 е причина за гастроинтестиналната токсичност и нарушената функция на тромбоцитите. За разлика от тях, селективните COX-2 инхибитори са насочени предимно към огнището на възпаление и са значително по-щадящи за стомаха и бъбреците.</p><h3>Основни принципи за приложение</h3><p>За постигане на оптимален ефект и намаляване на рисковете при употребата на НСПВС трябва да се спазват следните принципи:</p><ul><li><strong>Адекватно дозиране.</strong></li><li><strong>Оптимална продължителност на лечебния курс.</strong></li><li><strong>Правилно разпределение на предписаната доза в денонощието.</strong></li><li><strong>Индивидуална чувствителност към НСПВС.</strong></li><li><strong>Монотерапия.</strong></li><li><strong>Алтернативни форми:</strong> При нужда се използват ректални (свещички), парентерални (инжекционни) или перкутанни (гелове, мазила) форми на приложение.</li></ul><h3>Рискови фактори за стомашно-чревни нежелани реакции</h3><p>При лечение с НСПВС трябва да се подхожда с повишено внимание при пациенти, при които е налице повишен риск от усложнения. Основните рискови фактори включват:</p><ul><li><p>Висока доза или комбинация от НСПВС.</p><br></li><li><p>Продължителна употреба на НСПВС</p><br></li><li>Напреднала възраст (над 55–60 години).</li><li>Анамнестични данни за язвена болест или хроничен гастрит.</li><li>Едновременно приложение с антикоагуланти или глюкокортикоиди.</li><li>Наличие на сериозни съпътстващи заболявания като сърдечни болести или артериална хипертония.</li><li>Допълнителни фактори като инфекция с Helicobacter Pylori, тютюнопушене и злоупотреба с алкохол.</li></ul><p><strong>Терапевтично поведение при рискови болни:</strong></p><p>При наличие на рискови фактори за стомашно-чревния тракт се прилагат специфични стратегии за предпазване на пациента. В такива случаи се използват комбинирани лекарства, които съдържат едновременно:</p><ol><li><strong>НСПВС</strong> за справяне със ставната болка.</li><li><strong>Протектори</strong> на стомашната и дуоденалната лигавица за предпазване на стомаха.</li></ol><h2><hr>ІІ. Болестпроменящи антиревматични средства (БПАРС/DMARD)</h2><h3></h3>БПАРС са основната група медикаменти, които имат за цел да спрат прогресията на болестта. Те се подразделят на <strong>синтетични</strong> и <strong>биологични:</strong><ul><li><strong>Метотрексат</strong> (Златен стандарт)</li><li><strong>Арава</strong> (Лефлуномид)</li><li><strong>Сулфасалазин</strong></li><li><strong>Соли на златото</strong> (Солганал Б олеозум, Алокризин, Тауредон)</li><li><strong>Антималарици</strong> (Резохин, Плакенил)</li><li><strong>Други:</strong> Д-пенициламин, Азатиоприн (Имуран), Циклофосфамид, Циклоспорин А.</li></ul><h3>1. Метотрексат (Methotrexate)</h3><p>Средство на избор при болни с РА („златен стандарт“). Притежава много добра поносимост и сравнително бърз ефект (4–6 седмици).</p><ul><li><strong>Механизъм:</strong> Антагонист на фолиевата киселина.</li><li><strong>Дозировка:</strong> 7,5 – 25 мг седмично. Чревна резорбция: 20 – 80%.</li><li><strong>Нежелани лекарствени реакции:</strong></li><ul><li>Чести: Гастродуоденити и стоматити.</li><li>Редки, но сериозни: Пулмонит (овладява се с кортикостероиди).</li><li>Чернодробни: Фиброза и цироза (твърде редки – 1:1000 след 5-годишно лечение).</li><li>Други: Цитопения (супресия на костния мозък) или инфекции.</li></ul><li><strong>Контрол:</strong> АЛАТ, АСАТ, ГТП, АФ, креатинин, албумин и ПКК – първоначално ежемесечно, след това на 3 месеца.</li><li><strong>Противопоказания:</strong> Бременност, кърмене или активна инфекция.</li></ul><h3>2. Лефлуномид (Арава / Leflunomide)</h3><ul><li><strong>Механизъм:</strong> Инхибитор на пиримидиновия синтез.</li><li><strong>Дозировка:</strong> Начална „ударна“ доза от 100 мг (през първите 3 дни), последвана от поддържаща доза 20 мг ежедневно.</li><li><strong>НЛР:</strong> Диария, болки в стомаха, кожен обрив, обратима алопеция, токсичен хепатит, цитопения.</li><li><strong>Приложение:</strong> Ефективен при ранни и късни форми на РА. Контролът и противопоказанията са идентични с тези на Метотрексат.</li></ul><h3>3. Златни соли</h3><p>Прилагат се при липса на ефект или непоносимост към Метотрексат. Около 60–70% от пациентите показват подобрение. Използват се <strong>солганал Б, олеозум, алокризин, тауредон</strong> и др.</p><ul><li><strong>Схема на приложение (мускулно):</strong> </li><ul><li>1-ва седмица: 10 мг; 2-ра седмица: 25 мг; след това по 50 мг седмично до обща доза 1500–2000 мг.</li><li>Поддържаща доза: 50 мг на 2 седмици, по-късно – 50 мг ежемесечно в продължение на години.</li></ul><li><strong>Спиране:</strong> Ако при доза от 800 мг няма подобрение, лечението се прекратява.</li><li><strong>Токсичност:</strong> Около 1/3 от пациентите развиват реакции (дерматит, стоматит, неутропения, протеинурия, по-редки са токсичен хепатит и белодробна фиброза).</li><li><strong>Контрол:</strong> Преди всяка апликация – ПКК и урина за белтък, а първите 1-2 месеца и чернодробните ензими - АЛАТ, АСАТ, ГТП, АФ.</li><li><p><strong>Противопоказания:</strong> Бременност, кърмене или активна инфекция. </p><p>Не се започва терапията при предшестваща</p><p>тежка бъбречна, чернодробна или хемопоетична</p><p>дисфункция.</p><br></li><li><em>Забележка: На този етап вече не се предлагат на пазара.</em></li></ul><h3>4. Сулфасалазин (Sulfasalazine)</h3><p>Ефикасността му е съпоставима с тази на златото и пенициламина.</p><ul><li><strong>Дозировка:</strong> Започва се с 1 гр. дневно (за 7 дни), преминава се на 2 гр. При липса на ефект до 3 месеца – до 3 гр. дневно. Поддържаща доза: 1–2 гр в продължение на години.</li><li><strong>НЛР:</strong> </li><ul><li>По-редки и по-малко опасни.</li><li>Обикновено се установяват диспепсия, гадене, болки в корема, нервна напрегнатост. </li><li><p>Възможни са хематологични, чернодробни и</p><p>кожни нежелани лекарствени реакции.</p><br></li><li><p>Неутропения и тромбоцитопения развиват 10 –</p><p>25% от болните като в 2 – 5% са тежки.</p><br></li><li><strong>Специфичен риск:</strong> Индуцира хемолиза при пациенти с дефицит на ензима глюкозо-6-фосфат дехидрогеназа.</li></ul><li><strong>Контрол:</strong> ПКК, АЛАТ, АСАТ, ГТП на всеки 15 дни през първите 3 месеца, след това на 3 месеца.</li><li><p><strong>Противопоказания:</strong> Бременност и кърмене.</p><br></li></ul><h3>5. Други лекарствени препарати</h3><ul><li><strong>Антималарици (Резохин 250мг, Плакенил 200мг):</strong> По-слаб ефект, но и по-малка токсичност. Използват се за леки форми. Доза: 2х1 таб. за 20 дни, след което по 1 таб. дневно.</li><li><strong>Д-пенициламин, Азатиоприн, Циклоспорин, Циклофосфамид:</strong> Използват се значително по-малко поради изразени странични ефекти.</li></ul><h3>Обобщение на съвременния подход</h3><p>Лечението започва със <strong>синтетични БПАРС</strong>. Ако след 3-6 месеца няма ефект, се добавя <strong>биологично средство</strong> (антитела срещу цитокини – анти-ТНФ, анти-IL-6 или анти-B лимфоцити). Терапията е продължителна (месеци и години) до постигане на пълна или поне частична ремисия на заболяването.</p><h2><hr>ІІІ. <span class=\"editor-note\" data-note=\"**Биохимичен механизъм на действие на ГКС**\nГлюкокортикостероидите (ГКС) осъществяват своя ефект чрез сложни геномни и негеномни механизми, които потискат възпалителната каскада на молекулярно ниво. **1. Геномен механизъм (основен)**\nТова е бавният, но най-мощен път на действие:\n* **Свързване с рецептора:** ГКС преминават през клетъчната мембрана (поради своята липофилност) и се свързват с цитоплазмени глюкокортикоидни рецептори (GR).\n* **Транслокация:** Комплексът „лекарство-рецептор“ навлиза в клетъчното ядро.\n* **Трансрепресия:** Блокира транскрипционни фактори като **NF-κB** (ядрен фактор капа-Б) и **AP-1**, които са отговорни за синтеза на проинфламаторни цитокини (IL-1, IL-6, TNF-α).\n* **Трансактивация:** Стимулира синтеза на противовъзпалителни белтъци (напр. Липокортин-1). **2. Ензимна инхибиция**\nГКС влияят директно върху метаболизма на арахидоновата киселина:\n* **Инхибиране на Фосфолипаза А2 (PLA2):** Чрез стимулиране на белтъка липокортин, ГКС блокират освобождаването на арахидонова киселина от клетъчните мембрани.\n* **Резултат:** Потиска се синтеза както на **простагландини** (чрез COX), така и на **левкотриени** (чрез LOX), което води до мощно намаляване на отока и болката. **3. Клетъчни ефекти**\n* **Намаляване на съдовата пропускливост:** Предотвратяват излизането на левкоцити от кръвоносните съдове към огнището на възпаление (ставата).\n* **Стабилизиране на лизозомните мембрани:** Предотвратяват освобождаването на протеолитични ензими, които разрушават ставния хрущял.\" id=\"note-1771960117458-0\">Глюкокортикостероиди</span></h2><p>Глюкокортикостероидите притежават мощно противовъзпалително и умерено имуносупресивно действие. Техният ефект е много бърз и те драматично подобряват артрита, но <strong>не променят естествения му ход</strong>. Артритът се реактивира след спирането на ГКС. Много сериозен проблем са нежеланите лекарствени прояви вследствие на продължителното лечение.</p><h3>Основни принципи на приложение</h3><ul><li><strong>Временен характер:</strong> ГКС се изписват за кратко време при болни с висока възпалителна активност.</li><li><strong>Функция „Мост“:</strong> Използват се, докато започнат да действат болестопроменящите медикаменти (БПАРС) или за подпомагане на физикалното лечение.</li><li><strong>Профилактика:</strong> При хронично лечение с ГКС задължително трябва да се провежда профилактика на остеопорозата.</li><li><p><strong>Алтернативно приложение:</strong> ГКС могат да се включат при неповлияване на артрита от болестопроменящите медикаменти или при наличие на контраиндикации за тяхното приложение.</p><br></li></ul><h3>Дозировка и индикации</h3><ol><li><strong>Ниски дози (5 – 10 мг преднизолон):</strong> Това е най-често прилаганата доза за контрол на възпалението.</li><li><strong>Високи дози (40 – 60 мг дневно):</strong> Прилагат се при наличие на <strong>извънставни прояви</strong> като:</li><ul><li>Серозит;</li><li>Язви на роговицата;</li><li>Васкулит и др.</li></ul><li><strong>Пулс терапия (200 – 1000 мг метилпреднизолон):</strong> Провежда се в три последователни дни при следните състояния:</li><ul><li>Полиставно засягане с висока възпалителна активност;</li><li>Тежко ограничаване на функционалния капацитет на опорно-двигателния апарат;</li><li><u>Влошено общо състояние застрашаващо живота или орган</u>.</li></ul></ol><h3>Локално приложение (вътреставно и периставно)</h3><p>Вътреставни апликации се правят, когато въпреки системното лечение персистира отокът в една или две стави.</p><ul><li><strong>Препарати:</strong> Най-често се използват <em>Дипрофос, Флостерон, Депо Медрол</em>.</li><li><strong>Ефект:</strong> Повлияват синовита за период до три месеца.</li><li><strong>Ограничение:</strong> Не се препоръчват повече от <strong>3 апликации годишно</strong> в една и съща става.</li></ul><hr><h2>IV. Биологични средства</h2><p>Биологичните средства са съвременен клас медикаменти, които представляват моноклонални антитела срещу цитокини или техните рецептори, играещи ключова роля в патогенезата на РА.</p><h3>Основни характеристики и предимства:</h3><ul><li>Насочени са срещу специфични мишени като TNF-α, IL-6, IL-1 и CD20 рецепторите на B-лимфоцитите.</li><li>Терапевтичният ефект настъпва по-бързо в сравнение с метотрексат и се задържа във времето.</li><li>Потискат прогресирането на костно-хрущялните деструктивни промени в ставите.</li><li>Повлияват много добре функционалния капацитет на опорно-двигателния апарат и качеството на живот.</li><li>Приложени заедно с метотрексат, значително повишават своята ефективност.</li><li>Имат <strong>добра поносимост </strong>и рядко се налага прекъсване на лечението.</li></ul><h3>Класификация и препарати</h3><p><strong>1. Анти-TNF-α средства (TNF-алфа антагонисти)</strong></p><p>Действат чрез неутрализация на цитокините (чрез моноклонални антитела или разтворими рецептори).</p><ul><li><strong>Оригинални биологични средства:</strong></li><ul><li>Infliximab (Remicade)</li><li>Etanercept (Enbrel)</li><li>Adalimumab (Humira)</li><li>Golimumab (Simponi)</li><li>Certolizumab pegol (Cimzia)</li></ul><li><strong>Биоподобни:</strong></li><ul><li>Infliximab (Remsima)</li><li>Adalimumab (Hyrimoz, Amgevita, Hulio)</li></ul></ul><p><strong>2. Други биологични средства</strong></p><ul><li><strong>Анти-IL-1:</strong> Anakinra (Kineret)</li><li><strong>Анти-IL-6:</strong> Tocilizumab (RoACTEMRA)</li><li><strong>Анти-CD20 (върху B-лимфоцитите):</strong> Rituximab (Mabthera)</li></ul><h3>Нежелани лекарствени събития (анти-TNF клас)</h3><p>Приложението на тези средства изисква внимание поради риск от:</p><ul><li>Сериозни инфекции и опортюнистични инфекции (например хепатит B, C).</li><li>Туберкулоза (необходим е предварителен скрининг);</li><li>Демиелинизиращи заболявания;</li><li>Лупус-подобен синдром;</li><li>Хронична сърдечна недостатъчност;</li><li>Злокачествени заболявания (лимфоми и не-меланомен кожен карцином).</li></ul><h2><hr>Съвременно лечение на РА</h2><p>Съвременното лечение на ревматоидния артрит се базира на стриктен мониторинг и стъпаловиден подход, насочен към постигане на специфична цел (Treat-to-Target).</p><h3>Общи принципи и контрол</h3><ul><li><strong>Мониторинг:</strong> По време на лечението е задължително да се правят контролни кръвни изследвания.</li><li><strong>Наблюдение:</strong> Болният трябва да бъде проследяван от ревматолог и общопрактикуващ лекар за оценка на поносимостта и ранно откриване на нежелани лекарствени реакции.</li><li><strong>Хирургични методи:</strong> Прилагат се обикновено при напреднал стадий, когато ставите са тежко деформирани и с изгубена функция.</li><ul><li>Състоят се в протезиране на засегнатата става.</li><li>Хирургическо лечение на меките тъкани (сухожилия и техните влагалища).</li></ul></ul><hr><h2>EULAR Препоръки: Алгоритъм по фази</h2><p><strong>Основна цел:</strong> Постигане на клинична ремисия или (ако тя е малко вероятна) поне ниска болестна активност.</p><h3>Фаза I: Новодиагностицирани пациенти</h3><ul><li><strong>Първи подход:</strong> Използване на синтетично антиревматично лекарство.</li><li><strong>Средство на избор:</strong> <strong>Метотрексат</strong> – високоефективен, често се налага комбиниране с други средства.</li><li><strong>Алтернативи (при противопоказания за <p>Метотрексат</p>):</strong> Лефлуномид, сулфасалазин или интрамускулно злато.</li><li><strong>Оценка:</strong> Ако целта се постигне в рамките на <strong>3 до 6 месеца</strong>, терапията продължава. В противен случай се преминава към Фаза II.</li></ul><h3>Фаза II: Пациенти с неадекватен отговор на MTX</h3><ul><li><strong>При висока болестна активност:</strong> Препоръчва се добавяне на биологично лекарство, най-често <strong>TNF инхибитор</strong>.</li><li><strong>При липса на лоши прогностични фактори:</strong> Може да се опита второ синтетично антиревматично лекарство, модифициращо заболяването (монотерапия или комбинация), със или без глюкокортикоиди.</li><li><strong>Оценка:</strong> </li><ul><li><p>Ако целта на лечението е постигната в рамките на 3 до 6 </p><p>месеца, тогава продължете с втората терапия с DMARD; в </p><p>противен случай се препоръчва преминаване към биологична </p><p>терапия, особено с TNF инхибитор.</p></li><li>Ако и тогава няма резултат, се преминава към Фаза III.</li></ul></ul><h3>Фаза III: Пациенти с неуспех от първи TNF инхибитор</h3><p>Когато пациентът не реагира адекватно на първата биологична терапия, се предприемат следните стъпки:</p><ul><li><strong>Промяна в синтетичната терапия:</strong> Добавяне или смяна на синтетичния DMARD.</li><li><strong>Промяна в биологичното лечение:</strong></li><ul><li>Преминаване към <strong>втори TNF инхибитор</strong> + DMARD.</li><li><strong>Алтернативно заместване:</strong> Преминаване към биологично средство с друг механизъм:</li><ul><li>Абатацепт + DMARD;</li><li>Ритуксимаб + DMARD;</li><li>Тоцилизумаб (със или без DMARD).</li></ul></ul><li><strong>Оценка:</strong> Продължава се опитът с различни биологични средства на всеки 3 до 6 месеца, докато не бъде постигнат адекватен клиничен отговор.</li></ul><hr><h3></h3><h2>Аспекти на ремисията:</h2><ul><li><strong>Клинична ремисия</strong> – липса на признаци и симптоми на активно възпаление.</li><li><strong>Структурна ремисия</strong> – липса на рентгенова прогресия (спиране на ставната деструкция).</li><li><strong>Имунологична ремисия</strong> – нормализиране на имунологичните показатели.</li><li><strong>Функционална ремисия</strong> – пълно възстановяване на физическия капацитет и качеството на живот.</li></ul><hr><h2>Съвременен синтетичен подход</h2><p>Съвременният модел за борба с тази трудна за лечение болест включва следните ключови стратегии:</p><ul><li><strong>Ранна консултация:</strong> Своевременно диагностициране от специалист ревматолог.</li><li><strong>Ранно и агресивно лечение:</strong> Незабавно започване на терапия с БПАРС.</li><li><strong>Комбинирана терапия:</strong> Едновременно използване на няколко БПАРС за по-силен ефект.</li><li><strong>Иновативни медикаменти:</strong> Приложение на биологични средства и други нови лекарствени форми.</li><li><strong>Интердисциплинарно сътрудничество:</strong> Координация между ревматолози, физиотерапевти, ортопеди, психолози и др.</li><li><strong>Дългосрочна стратегия:</strong> Постоянно мониториране на хода на болестта и адаптиране на лечението на всеки етап, за да се постигне оптимална последователност от медикаменти.</li></ul><hr><h2>Заключение</h2><ol><li><strong>Природа на заболяването:</strong> Ревматоидният артрит е автоимунно, възпалително ставно заболяване с хронично прогресиращ ход. То засяга много или всички стави и води до <strong>инвалидизиране</strong>, ако не се лекува или се лекува неадекватно.</li><li><strong>Критичен период:</strong> При 60% от пациентите се наблюдава <strong>необратимо увреждане</strong> още в рамките на първите 2 години от поставяне на диагнозата.</li><li><strong>Цели на лечението:</strong> Съвременното лечение е комплексно и е насочено към:</li><ul><li>Овладяване на болестната активност;</li><li>Ограничаване на структурните увреждания;</li><li>Намаляване на инвалидизацията.</li></ul><li><strong>Важност на ремисията:</strong> Постигането на ремисия в ранната фаза на РА е ключовият фактор за предотвратяване на трайната инвалидизация.</li></ol><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><h1 style=\"text-align: center\">Тема 45: Системен еритематоден лупус – клиника, диагностични критерии и лечение.</h1><h2>Определение и епидемиология</h2><ul><li>Системният лупус еритематозус (СЛЕ) представлява прототип на хронично мултисистемно автоимунно заболяване. Характеризира се с генериране на автоантитела срещу нуклеарни антигени и фактори на коагулацията, което води до имунно-медиирано увреждане на практически всеки орган или система.</li><li><strong>Честота и разпространение</strong>:</li><ul><li>Честотата варира от 12 до 50 случая на 100 000 души.</li><li>Заболяването е по-често срещано в Северна Америка, отколкото в Европа.</li></ul><li><strong>Полови и възрастови характеристики</strong>:</li><ul><li>Налице е силно изразено превалиране на женския пол, като съотношението жени:мъже е 9-10:1.</li><li>Най-засегната е възрастовата група между 15 и 64 години (фертилен период).</li><li>При децата и възрастните над 65 години съотношението между половете е по-слабо изразено (около 2:1 до 3:1).</li></ul><li><strong>Етнически различия</strong>: Заболяването засяга по-често и протича по-тежко (с по-висока честота на лупусен нефрит и невролупус) при представителите на афро-американската и азиатската популация.</li></ul><h2><hr></h2><h2>Етиология</h2><p>Етиологията на СЛЕ е мултифакторна, включваща взаимодействие между генетична предиспозиция, хормонални влияния и екзогенни тригери от околната среда.</p><h3>Генетични фактори</h3><p>Генетичната компонента определя индивидуалната чувствителност към заболяването чрез няколко механизма:</p><ul><li><strong>HLA асоциации</strong>: Наличието на алелите HLA-DR2 и HLA-DR3 е свързано с повишен риск. Тези молекули от II клас на главния комплекс за тъканна съвместимост (MHC) презентират собствени антигени на Т-лимфоцитите по-ефективно, което улеснява загубата на имунен толеранс.</li><li><strong>Дефицит на комплемента</strong>: Хомозиготните дефекти в ранните компоненти на комплемента (C1q, C4a, C2) са ключов фактор. Тези протеини са отговорни за опсонизацията и клирънса на апоптозните тела. При техния дефицит се натрупва ядрен материал, който служи като източник на автоантигени<p>,които стимулират </p><p>автореактивните Т-клетки и продукцията на IFNα.</p></li><li><strong>Не-HLA генетични локуси</strong>: Вариации в гените TREX1 (нуклеаза), STAT4 (трансдукция на цитокинови сигнали), IRF5 (интерферонов регулаторен фактор) и TNFAIP3 се асоциират със свръхактивация на вродения имунитет.</li></ul><h3>Фактори на околната среда (Екзогенни тригери)</h3><p>Тези фактори действат като инициатори на имунния отговор при генетично предразположени индивиди:</p><ul><li><strong>Ултравиолетова радиация (UVB)</strong>: Индуцира директно увреждане на ДНК и апоптоза на кератиноцитите. UVB лъчите променят структурата на нуклеиновите киселини, правейки ги по-имуногенни, и стимулират секрецията на проинфламаторни цитокини (IL-1, IL-6).</li><li><strong>Вирусни инфекции</strong>: Вирусът на Епщайн-Бар (EBV) се свързва с патогенезата чрез механизъм на \"молекулярна мимикрия\" – имунната система атакува собствени протеини, които наподобяват вирусните антигени.</li><li><strong>Химически субстанции</strong>: Тютюнопушенето повишава нивата на оксидативен стрес и ДНК метилирането. Експозицията на силициев диоксид действа като адювант за имунната система.</li></ul><h3>Хормонални фактори</h3><ul><li><strong>Роля на естрогените</strong>: Естрогените засилват хуморалния имунен отговор чрез стимулиране на В-лимфоцитната пролиферация и потискане на Т-супресорната активност. Това обяснява високата честота при жени във фертилна възраст и влошаването на състоянието при прием на хормонална заместителна терапия или орални контрацептиви.</li></ul><h2><hr></h2><h2>Патогенеза</h2><p>Патогенетичният процес се инициира от продукцията на антигени по време на апоптоза и тяхното нарушено разграждане.</p><h3>Имунологична каскада:</h3><ol><li><strong>Активиране на вродения имунитет</strong>: Повишеното количество свободни нуклеинови киселини, освободени след апоптоза на клетките, се свързват с <strong>Toll-like рецептори</strong> върху плазмацитоидните дендритни клетки.</li><li><strong>Роля на IFNa</strong>: Дендритните клетки произвеждат <strong>Интерферон-алфа (IFNa)</strong>, който е ключов медиатор за активирането на Т- и В-лимфоцитите.</li><li><strong>Автоантителна продукция</strong>: Основното отклонение при СЛЕ е масивната продукция на автоантитела, като 95% от тях са антинуклеарни антитела (<strong>ANA</strong>).</li></ol><h3>Спектър на антителата:</h3><ul><li><strong>Антинуклеарни антитела (ANA)</strong>:</li><ul><li><strong>анти-dsDNA </strong> – специфични за СЛЕ; пряко свързани с развитието на гломерулонефрит.</li><li><strong>анти-Sm </strong>– патогмонични и високо специфични за СЛЕ.</li><li><strong>анти-RNP</strong>, <strong>анти-Ro (SSA)</strong>, <strong>анти-La (SSB)</strong> – към разтворими рибонуклеопротеини.</li></ul><li><strong>Други автоантитела</strong>:</li><ul><li>Към кръвните клетки – причиняват цитопении (анемия, левкопения, тромбоцитопения).</li><li>Към факторите на коагулацията.</li><li><strong>Антифосфолипидни антитела</strong> – причиняват съдови тромбози, спонтанни аборти и тромбоцитопения.</li><li>Антицитоплазматични антитела.</li></ul></ul><h4>Механизми на тъканно увреждане:</h4><ul><li><strong>Имунни комплекси</strong>: Депозирането на комплекси (антиген-антитяло) в тъканите предизвиква имунно възпаление и увреждане на съдовете под формата на <strong>васкулит</strong>.</li><li><strong>Директна атака</strong>: Увреждане на органите чрез клетъчно-медиирана цитотоксичност или директна антителна атака срещу специфични клетъчни структури.</li><li><strong>Бъбречно увреждане</strong>: Антинуклеарните антитела (предимно анти-dsDNA) са директно отговорни за патогенезата на лупусния гломерулонефрит.</li></ul><h2><hr></h2><h2>Клинична картина и клинични форми</h2><p>В началото на заболяването и при обостряне се наблюдават общи (конституционални) симптоми: изразена отпадналост, лесна уморяемост, фебрилитет и прогресивна загуба на тегло.</p><h3>1. Кожни и лигавични промени</h3><ul><li><strong>Пеперудообразен еритем</strong>: Патогномоничен белег. Представлява надигната еритемна лезия (сърбяща или болезнена), обхващаща скулите и основата на носа, като назолабиалните гънки остават свободни.</li><li><strong>Остри и подостри кожни промени</strong>: Генерализиран еритем, булозни лезии, ануларни и папуло-сквамозни обриви (наподобяващи псориазис или лихен планус).</li><li><strong>Хронични лезии</strong>: </li><ul><li><em>Lupus discoides</em> (дискоиден лупус) – хронична лезия, оставяща цикатрикси (белези).</li><li><em>Лупусен паникулит</em> – образуване на нодули в дълбоките слоеве на дермата и подкожната мастна тъкан.</li></ul><li><strong>Васкулит на кожата</strong>: Инфаркти на нокътното ложе, улцерации по пръстите, палмарен васкулит, <em>livedo reticularis</em> и уртико-петехиални обриви.</li><li><strong>Лигавици</strong>: Ерозии и улцерации в устната и носната кухина. Най-характерни са <strong>неболезнените афти по твърдото небце</strong>.</li><li><strong>Фоточувствителност</strong>: Повечето болни имат повишена чувствителност към слънце, което води до кожни обриви и системно обостряне.</li><li><strong>Алопеция</strong>: Дифузна или огнищна, появяваща се при активност на заболяването.</li></ul><h3>2. Двигателна система</h3><ul><li><strong>Артрит и артралгии</strong>: Честа проява със симетрично обхващане на периферните стави (МКФ, ПИФ), гривнените и коленните стави. За разлика от РА, тук артритът е <strong>неерозивен</strong>.</li><li><strong>Артрит на Jaccoud</strong>: (при 10-35% от пациентите) – деформации тип „лебедова шия“, улнарна девиация и сублуксации на МКФ ставите. Дължат се на <strong>лакситет (разхлабване) на ставните капсули</strong>, сухожилия и лигаменти (ставна хипермобилност).</li><li><strong>Rhupus форма</strong>: Рядък симетричен ерозивен полиартрит с положителен RF.</li><li><strong>Асептична некроза</strong>: Най-често засяга главата на бедрената кост; свързва се с употребата на кортикостероиди.</li><li><strong>Синдром на Raynaud</strong>: Вторичен, в 1/3 от случаите, дължащ се на васкулит на периферните съдове.</li></ul><h3>3. Полисерозит</h3><ul><li><strong>Ексудативен плеврит</strong>: Малки, често двустранни изливи. Ексудатът се характеризира с нормална глюкоза, нисък комплемент и наличие на АНА и имунни комплекси.</li><li><strong>Перикардит</strong>: Най-честото сърдечно увреждане. Клинично се изявява с прекордиална болка и перикардно триене.</li><li><strong>Дифузен перитонит</strong>: Коремна болка, безапетитие, гадене и малък асцит (с положителни АНА в асцитната течност).</li></ul><h3>4. Лупусна нефропатия (Бъбречно засягане)</h3><p>Развива се при около 45% от болните. Често е безсимптомна до напреднал стадий.</p><ul><li><strong>Лабораторни критерии</strong>: Протеинурия &gt;500 mg/24ч, хематурия, пиурия (без инфекция) и цилиндрурия (еритроцитни, гранулирани, хиалинни или смесени цилиндри).</li><li><strong>Диагноза</strong>: Бъбречната биопсия е „златен стандарт“ за точна диагноза на типа увреждане.</li></ul><h3>5. Невро-психиатрични прояви (Невролупус)</h3><ul><li><strong>Дифузно засягане</strong>: Главоболие (мигренозно, резистентно на аналгетици), генерализирани припадъци, асептичен менингит, когнитивни нарушения, психоза. Свързва се с <strong>антиневронални антитела</strong> и цитокинова активност.</li><li><strong>Огнищно засягане</strong>: Инсултоподобни състояния, хорея, трансверзален миелит (парализа на долни крайници). Свързва се със съдова оклузия и <strong>антифосфолипидни антитела</strong>.</li><li><strong>Органичен мозъчен синдром</strong>: Увреждане на паметта, концентрацията и емоционална нестабилност поради множествени микроинфаркти или цереброваскулит.</li></ul><h3>6. Белодробни и сърдечни прояви</h3><ul><li><strong>Бели дробове</strong>: </li><ul><li><strong>Лупусен пневмонит</strong>: Остра форма (наподобява пневмония) или хронична форма (със задух, суха кашлица и базална пулмофиброза).</li><li><strong>Пулмонален васкулит</strong>: Протича с хемоптое (храчене на кръв).</li><li><strong>Пулмонална хипертензия</strong>: Изразен задух при нормална рентгенография; често вторична при АФС и тромбоемболии.</li></ul><li><strong>Сърце</strong>: </li><ul><li><strong>Миокардит</strong>: Тахикардия, ритъмни нарушения и сърдечна недостатъчност.</li><li><strong>Ендокардит на Libman-Sacks</strong>: Класически вегетации, най-често причиняващи инсуфициенция (недостатъчност) на митралната клапа.</li><li><strong>Акцелерирана атеросклероза</strong>: Повишен СС-риск поради възпалението, хипертонията и стероидната терапия.</li></ul></ul><h3>7. Гастроинтестинална система</h3><div><p>Симптомите от страна на ГИТ обикновено се свързват със СЛЕ само при наличие на доказана активност на заболяването и в други органи. Характерни прояви са:</p></div><ul><li><strong>Хепатомегалия</strong>: Честа находка с повишени чернодробни ензими.</li><li><strong>Остър панкреатит</strong>: <p>Абдоминална болка, гадене, повръщане и хиперамилаземия (повишена серумна амилаза).</p>.</li><li><strong>Мезентериален васкулит</strong>: Интермитентна болка в долния коремен етаж.</li><li><strong>Възпалителни промени на червата</strong>: Разязвявания по колона и ректални кръвоизливи.</li><li><p><strong>Дифузен перитонит</strong>: Клинично се представя с коремна болка и безапетитие, често съчетан с малък асцит.</p><br></li></ul><h3>8. Ретикулоендотелна система (РЕС)</h3><div><p>В активен стадий на заболяването при повечето болни се установяват:</p></div><ul><li><strong>Лимфаденомегалия</strong>: Генерализирана, възлите са меки и неболезнени.</li><li><strong>Спленомегалия</strong>.</li></ul><h3>9. Очно засягане</h3><ul><li><strong>Ретинален васкулит</strong>: Най-честата форма на очно засягане.</li><li><strong>Инфаркти на ретиналните съдове</strong>: Обикновено са резултат от наличието на антифосфолипидни антитела.</li><li><strong>Вторичен синдром на Сьогрен</strong>: Протича с клиничната картина на сух кератоконюнктивит.</li><li><strong>Медикаментозно индуцирани увреждания</strong>:</li><ul><li><strong>Ретинопатия</strong>: Като страничен ефект от продължително лечение с антималарици.</li></ul><ul><li><strong>Катаракта и повишено вътреочно налягане (глаукома)</strong>: В резултат на системна употреба на кортикостероиди.</li></ul></ul><div><span style=\"color: rgb(88, 129, 87); font-weight: 600\"><br></span></div><h3>Протичане и късни усложнения</h3><div><p>С подобряването на преживяемостта при СЛЕ се наблюдава т.нар. <strong>напреднал стадий на лупуса</strong>, за който са характерни следните късни усложнения:</p><ol><li><strong>Хронична бъбречна болест </strong>– резултат от лупусната нефропатия.</li><li><strong>Напреднала атеросклероза</strong> – с повишен риск от сърдечно-съдови инциденти.</li><li><strong>Пулмонални емболии</strong>.</li><li><strong>Аваскуларна остеонекроза</strong>.</li><li><strong>Трайно засягане на ЦНС</strong> (невропсихични прояви).</li></ol></div><div><h2><hr>Специфични клинични форми, протичане и усложнения</h2><p>Освен класическото протичане на СЛЕ, съществуват няколко специфични клинични форми и стадии:</p><h3>Особени клинични форми</h3><ul><li><strong>Субклиничен лупус</strong>: Наблюдава се при пациенти с отделни симптоми на заболяването, които не са достатъчни за покриване на диагностичните критерии. Това състояние може да персистира години, като в някои случаи симптомите изчезват и остават само имунологичните феномени.</li><li><strong>Лекарствено-предизвикан лупус</strong>: Развива се след прием на определени медикаменти (<em>Chlorpromazin, Methyldopa, Hydralazin, Procainamid, Isoniazid</em> и др.). </li><ul><li><strong>Характеристики</strong>: Среща се по-често при лица над 50 г. с еднаква честота при двата пола. </li><li><strong>Клинична картина</strong>: Обикновено протича леко с конституционални симптоми, артралгии, миалгии, еритемо-папулозен обрив и серозит. Рядко се засягат ЦНС и бъбреците.</li><li><strong>Лаборатория</strong>: Цитопения, наличие на АНА (предимно към хистони и едноверижна ДНК) и положителен РФ. </li><li><strong>Прогноза</strong>: Спирането на медикамента води до пълно излекуване.</li></ul><li><strong>Антифосфолипиден синдром</strong>: Проявява се с артериални и венозни тромбози, рецидивиращи спонтанни аборти, имунна тромбоцитопения и наличие на антифосфолипидни антитела.</li></ul></div><hr><h2></h2><h2></h2><h2>Лабораторни промени при СЛЕ</h2><p>При наличие на възпалителна активност на заболяването се наблюдава ускорена скорост на утаяване на еритроцитите (<strong>СУЕ</strong>).</p><h3>А. Хематологични промени</h3><p>При СЛЕ характерни са цитопениите и нарушенията в съсирването на кръвта:</p><ul><li><strong>Автоимунна хемолитична анемия</strong>: Развива се вследствие на наличието на антиеритроцитни автоантитела; диагностицира се с положителен <strong>тест на Coombs</strong>.</li><li>Установява се също <strong>л</strong><strong>евкопения, лимфоцитопения, тромбоцитопения.</strong></li></ul><p><strong>При съпътстващ антифосфолипиден синдром (АФС) се установяват:</strong></p><ul><li>Лупусен антикоагулант.</li><li>Антикардиолипинови антитела.</li><li>Антитела срещу β2 гликопротеин I.</li><li>Удължено парциално тромбопластиново време (aPTT).</li><li>Фалшиво положителна проба на Wassermann (тест за сифилис).</li></ul><h3>Б. Имунологични промени</h3><p>Имунологичният профил е от критично значение за диагнозата и проследяването на активността:</p><ol><li><strong>Диагностично значими антитела</strong>:</li><ul><li><strong>Аnti-dsDNA</strong>.</li><li><strong>Аnti-Sm</strong>.</li></ul><li><strong>Система на комплемента</strong>:</li><ul><li>Снижени стойности на тоталния хемолитичен комплемент (CH50).</li><li>Снижени нива на <strong>С3- и С4-фракциите</strong> на комплемента (белег за консумация при активност).</li></ul><li><strong>Други автоантитела</strong>:</li><ul><li>Могат да се позитивират: антихистонови, анти-SSA (Ro), анти-SSB (La), анти-RNP антитела, както и ревматоиден фактор (RF).</li></ul></ol><h2><hr>Диагноза</h2><p>За поставяне на сигурна диагноза СЛЕ се използват класификационните критерии на <strong>ACR (1982)</strong>. Диагнозата се счита за потвърдена при наличието на <strong>поне 4 от 11 критерия</strong>, които могат да се изявят едновременно или последователно във времето.</p><h3>Класификационни критерии на ACR:</h3><ol><li><strong>Пеперудообразен обрив</strong>: Еритем над нивото на кожата в областта на скулите, който задължително щади назолабиалните гънки.</li><li><strong>Дискоиден лупус</strong>: Еритемни плаки със сквами (люспи) по повърхността; при по-стари лезии се развива атрофия.</li><li><strong>Фоточувствителност</strong>: Кожни лезии, развиващи се като необичайна реакция към слънчева светлина (по данни от пациента или наблюдение от лекар).</li><li><strong>Орална или назофарингеална афтоза</strong>: Обикновено безболезнени улцерации в устната кухина или назофаринкса, установени от лекар.</li><li><strong>Артрит</strong>: Неерозивен артрит, засягащ 2 или повече периферни стави (характеризира се с чувствителност, оток или излив).</li><li><strong>Серозит</strong>:</li><ul><li><em>Плеврит</em>: Анамнеза за плеврална болка или аускултирано плеврално триене.</li><li><em>Перикардит</em>: Документиран чрез ЕКГ, перикардно триене или ехографски доказан излив.</li></ul><li><strong>Лупусен нефрит</strong>:</li><ul><li>Персистираща протеинурия над 0.5 г/24ч (или над 3+ при качествено изследване).</li><li>Наличие на клетъчни цилиндри (еритроцитни, хемоглобинови, гранулирани или смесени).</li></ul><li><strong>Неврологично ангажиране</strong>:</li><ul><li>Припадъци или Психоза (при липса на метаболитни нарушения като уремия, кетоацидоза или медикаменти).</li></ul><li><strong>Хематологично ангажиране</strong>:</li><ul><li>Хемолитична анемия с ретикулоцитоза.</li><li>Левкопения (&lt; 4 000/мм³ в две или повече изследвания).</li><li>Лимфопения (&lt; 1 500/мм³ в две или повече изследвания).</li><li>Тромбоцитопения (&lt; 100 000/мм³ при липса на медикаменти).</li></ul><li><strong>Имунологични прояви</strong>:</li><ul><li>Положителни <strong>anti-dsDNA</strong> антитела.</li><li>Положителни <strong>anti-Sm</strong> антитела.</li><li>Антифосфолипидни антитела (повишен IgG/IgM антикардиолипин, лупусен антикоагулант или фалшиво положителен тест за сифилис над 6 месеца).</li></ul><li><strong>Позитивна проба за ANA</strong>: Положителни общи антинуклеарни антитела чрез имунофлуоресценция в титър &gt;1:160 (при отсъствие на медикаменти).</li></ol><h2><hr>Диференциална диагноза</h2><p>Поради мултисистемния характер на заболяването, СЛЕ трябва да се различава от широк спектър патологии:</p><ul><li><strong>Инфекции</strong>: Сепсис.</li><li><strong>Хематологични заболявания</strong>: Малигнени хемопатии (левкемии, лимфоми).</li><li><strong>Други системни заболявания на съединителната тъкан</strong>:</li><ul><li>Ревматоиден артрит (РА).</li><li>Синдром на Sjogren.</li><li>Смесена съединителнотъканна болест (ССТБ).</li><li>Полиартериитис нодоза и други васкулити.</li><li>Синдроми на припокриване (Overlap syndromes).</li></ul><li><strong>Пулмо-ренални синдроми</strong>: ANCA-асоциирани васкулити, синдром на Goodpasture.</li><li><strong>Други</strong>: Хроничен активен хепатит.</li></ul><div><h2><hr>Лечение и профилактика</h2><p><strong>Цели на лечението</strong>: Удължаване на живота, предотвратяване на органна увреда и подобряване на качеството на живот чрез контрол над болестната активност, коморбидностите и лекарствената токсичност.</p><h3>Общи мерки и режим</h3><ul><li><strong>Режим</strong>: Болничен при активен стадий; свободен при ремисия.</li><li><strong>Диета</strong>: Пълноценна храна, богата на витамини.</li><li><strong>Обучение на пациента</strong>: Използване на слънцезащитни кремове, избягване на ненужен прием на антибиотици, алергизираща козметика и имунизации.</li></ul><h3>Медикаментозно лечение</h3><ol><li><strong>Симптоматични средства</strong>: <strong>НСПВС</strong> в терапевтични дози за овладяване на фебрилитет, артрит и серозит.</li><li><strong>Антималарични средства (Chloroquin, Hydroxychloroquin)</strong>:</li><ul><li>Избор при кожно-лигавични и ставни прояви.</li><li>Намаляват пристъпите на активност и профилактират тромбози при АФС.</li><li>Благоприятен ефект върху липидния и кръвно-захарния профил. Разрешени при бременност.</li></ul><li><strong>Кортикостероиди (КС)</strong>: Основно средство (Prednisolon, Methylprednisolon).</li><ul><li>При висока активност се започва с високи дози, които след ремисия се намаляват стъпаловидно до поддържащи.</li><li><strong>Пулсово лечение</strong>: 1g Methylprednisolon i.v. за 3 дни при лупусен нефрит или невролупус.</li></ul><li><strong>Имуносупресори</strong>:</li><ul><li><strong>Azathioprine (Imuran)</strong>: 2-3 mg/kg/дн. Потиска Т- и В-лимфоцитите.</li><li><strong>Cyclophosphamide (Endoxan)</strong>: Алкилиращ цитостатик, използван парентерално (пулсово) при тежки форми. Силно цитотоксичен.</li><li><strong>Cyclosporin A</strong>: Инхибира IL-2 и IL-17; стабилизира подоцитите (намалява протеинурията).</li><li><strong>Mycophenolate mofetil (Cellcept)</strong>: Инхибира пролиферацията на Т-лимфоцитите. Максимална доза 3g/дн.</li></ul><li><strong>Имуноглобулин (i.v. във високи дози)</strong>: При лупусна тромбоцитопения, АФС, инфекции или активен лупус по време на бременност.</li><li><strong>Биологични средства</strong>:</li><ul><li><strong>Belimumab (Benlysta)</strong>: Срещу BLyS; при висока имунологична активност (високи anti-dsDNA, нисък комплемент). Не е за нефрит/невролупус.</li><li><strong>Rituximab (Mabthera)</strong>: Срещу CD20 на В-клетките; при лупусен нефрит и рефрактерен лупус.</li></ul></ol><h3>Немедикаментозно лечение</h3><ul><li><strong>Плазмафереза</strong>: При тежки форми с бързо прогресираща нефропатия или неврологични усложнения.</li><li><strong>Диализа и трансплантация</strong>: При терминална бъбречна недостатъчност.</li></ul><h3>Вторична профилактика</h3><ul><li><strong>Фотосензитивност</strong>: Кремове с парааминобензоена киселина.</li><li><strong>Бременност</strong>: Само в стадий на ремисия; противопоказана при лупусна нефропатия.</li><li><strong>Ваксинации</strong>: Принципно противопоказани; по изключение (противогрипна, пневмококова) само при неактивен лупус под лекарски контрол.</li><li><strong>Профилактика на усложненията</strong>: Калций и Витамин D (срещу остеопороза от КС), контрол на кръвно налягане и липиди.</li></ul><h3>Прогноза и трудоспособност</h3><ul><li><strong>Прогноза</strong>: Сериозна, но ранното лечение я подобрява значително.</li><li><strong>Трудоспособност</strong>: Пациентите са нетрудоспособни при активност. В ремисия се възстановява частично, при условие че се избягват вредни активиращи фактори (слънце, токсини).</li></ul></div><ol></ol><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><h1 style=\"text-align: center\">Тема 46: Кортикостероиди – класификация, механизъм на действие, странични ефекти и клинично приложение.</h1><br><br><br>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\[', right: '\\]', display: true},\n    {left: '\\(', right: '\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
